// Auto-generated mapping (HSN -> Description) + GST slab range lookup.
// Sources:
// - HSN descriptions: HSN-Codes-for-GST-Enrolment_copy.pdf
// - GST slabs: FINAL_GST_RANGE_MASTER_CORRECTED.xlsx (sheet: GST_SLAB_MASTER_CORRECTED)

export type GstPercent = string;

export type GstSlabRange = {
  slRange: string;
  from: number;   // inclusive (HSN heading as integer, e.g. 0101 => 101)
  to: number;     // inclusive
  gstPercent: GstPercent; // e.g. "0%", "5%", "12%", "18%", "28%", "5% / 18%"
  remarks?: string;
};

export type HsnInfo = {
  input: string;
  normalized: string;          // digits only
  matchedDescriptionCode?: string;
  description?: string;
  headingForGst?: number;      // integer based on first 4 digits (or less if input is shorter)
  gstPercent?: GstPercent;
  gstSlabRange?: string;
  gstRemarks?: string;
  gstFrom?: number;
  gstTo?: number;
};

/** Digits-only normalization (removes dots, spaces, hyphens, etc.). */
export function normalizeHsn(input: string | number): string {
  const raw = String(input ?? "").trim();
  return raw.replace(/\D+/g, "");
}

/**
 * Best-effort description lookup:
 * - Try exact match first (e.g. 01012100)
 * - Then fallback by truncating to 8/6/4/2 digits (common HSN lengths)
 */
export function findBestDescription(normalizedHsn: string): { code?: string; description?: string } {
  const h = (normalizedHsn || "").replace(/\D+/g, "");
  if (!h) return {};
  const candidates: string[] = [];

  // exact
  candidates.push(h);

  // typical truncations
  const cut = (n: number) => (h.length >= n ? h.slice(0, n) : "");
  [8, 6, 4, 2].forEach((n) => {
    const v = cut(n);
    if (v && v !== h) candidates.push(v);
  });

  // last resort: trim by 1 until 2 digits (rarely needed)
  for (let n = Math.min(h.length - 1, 10); n >= 2; n--) {
    const v = h.slice(0, n);
    if (v && !candidates.includes(v)) candidates.push(v);
  }

  for (const c of candidates) {
    const d = HSN_DESCRIPTION[c];
    if (d) return { code: c, description: d };
  }
  return {};
}

