/**
 * Uses GST slab ranges from Excel. Matching is done using an integer derived from:
 * - first 4 digits (HSN heading) when available; else the whole input digits.
 * Example: "01012100" => heading "0101" => int 101.
 */
export function getGstByHsn(input: string | number): {
  headingForGst?: number;
  gstPercent?: GstPercent;
  gstSlabRange?: string;
  gstRemarks?: string;
  gstFrom?: number;
  gstTo?: number;
} {
  const normalized = normalizeHsn(input);
  if (!normalized) return {};

  const headingStr = normalized.length >= 4 ? normalized.slice(0, 4) : normalized;
  const headingForGst = Number(headingStr); // drops leading zeros; desired for matching Excel ranges

  if (!Number.isFinite(headingForGst)) return {};

  const slab = GST_SLAB_RANGES.find((r) => headingForGst >= r.from && headingForGst <= r.to);
  if (!slab) return { headingForGst };

  return {
    headingForGst,
    gstPercent: slab.gstPercent,
    gstSlabRange: slab.slRange,
    gstRemarks: slab.remarks,
    gstFrom: slab.from,
    gstTo: slab.to,
  };
}

/** High-level helper: returns description + GST slab info in one call. */
export function getHsnInfo(input: string | number): HsnInfo {
  const normalized = normalizeHsn(input);

  const { code: matchedDescriptionCode, description } = findBestDescription(normalized);
  const gst = getGstByHsn(normalized);

  return {
    input: String(input ?? ""),
    normalized,
    matchedDescriptionCode,
    description,
    ...gst,
  };
}

